config {
    type: "incremental",
    schema: "warranty_data",
    name: "stg_warranty_claims",
    uniqueKey: ["claim_id"],
    bigquery: {
        partitionBy: "claim_date",
        updatePartitionFilter: "claim_date >= DATE_SUB(CURRENT_DATE(), INTERVAL 1 DAY)"
    },
    description: "Incremental table for warranty claims with data validation.",
    assertions: {
        uniqueKey: ["claim_id"],
        nonNull: ["claim_id", "claim_date", "model"]
    }
}

-- Pre-operations: Logging or custom source validation
pre_operations {
  -- Ensure the source data isn't unexpectedly empty before processing
  ASSERT (SELECT COUNT(*) FROM ${ref("warranty_claims_source")}) > 0 
    AS "Source warranty_claims table is empty";
}

SELECT
  claim_id,
  model,
  dealer,
  -- Handle 'NA' strings in mileage and convert to integer
  SAFE_CAST(NULLIF(mileage, 'NA') AS INT64) AS mileage,
  -- Address negative repair costs found in raw data
  ABS(repair_cost) AS repair_cost,
  failure_code,
  CAST(claim_date AS DATE) AS claim_date
FROM
  ${ref("warranty_claims_source")}

${when(incremental(), `WHERE claim_date > (SELECT MAX(claim_date) FROM ${self()})` )}

-- Post-operations: Data Quality Checks
post_operations {
  -- Validation: Ensure no repair costs are still negative after processing
  ASSERT (SELECT COUNT(*) FROM ${self()} WHERE repair_cost < 0) = 0 
    AS "Data Error: Negative repair costs detected in processed table";

  -- Validation: Check for unreasonable mileage entries
  ASSERT (SELECT COUNT(*) FROM ${self()} WHERE mileage > 500000) = 0 
    AS "Data Warning: Extreme mileage (>500k) detected";
}

import React, { useState, useMemo } from 'react';

const MOCK_DATA = [
  { id: 1, customer: "John Doe", product: "Laptop X1", date: "2023-10-01", status: "Pending", amount: 1200 },
  { id: 2, customer: "Jane Smith", product: "Phone Z", date: "2023-09-15", status: "Approved", amount: 800 },
  { id: 3, customer: "Bob Johnson", product: "Tablet A", date: "2023-10-05", status: "Rejected", amount: 300 },
  { id: 4, customer: "Alice Brown", product: "Laptop X1", date: "2023-08-20", status: "Approved", amount: 1150 },
  { id: 5, customer: "Charlie Davis", product: "Smartwatch S", date: "2023-10-10", status: "Pending", amount: 250 },
];

const WarrantyClaimsTable = () => {
  const [claims] = useState(MOCK_DATA);
  const [searchTerm, setSearchTerm] = useState("");
  const [statusFilter, setStatusFilter] = useState("All");
  const [sortConfig, setSortConfig] = useState({ key: 'date', direction: 'desc' });

  // Handle Filtering and Sorting logic
  const filteredAndSortedClaims = useMemo(() => {
    let result = claims.filter((item) => {
      const matchesSearch = item.customer.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            item.product.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesStatus = statusFilter === "All" || item.status === statusFilter;
      return matchesSearch && matchesStatus;
    });

    if (sortConfig.key) {
      result.sort((a, b) => {
        if (a[sortConfig.key] < b[sortConfig.key]) {
          return sortConfig.direction === 'asc' ? -1 : 1;
        }
        if (a[sortConfig.key] > b[sortConfig.key]) {
          return sortConfig.direction === 'asc' ? 1 : -1;
        }
        return 0;
      });
    }
    return result;
  }, [claims, searchTerm, statusFilter, sortConfig]);

  const requestSort = (key) => {
    let direction = 'asc';
    if (sortConfig.key === key && sortConfig.direction === 'asc') {
      direction = 'desc';
    }
    setSortConfig({ key, direction });
  };

  return (
    <div style={{ padding: '20px', fontFamily: 'sans-serif' }}>
      <h2>Warranty Claims</h2>

      {/* Controls */}
      <div style={{ marginBottom: '20px', display: 'flex', gap: '10px' }}>
        <input
          type="text"
          placeholder="Search customer or product..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          style={{ padding: '8px', width: '250px' }}
        />
        <select 
          value={statusFilter} 
          onChange={(e) => setStatusFilter(e.target.value)}
          style={{ padding: '8px' }}
        >
          <option value="All">All Statuses</option>
          <option value="Pending">Pending</option>
          <option value="Approved">Approved</option>
          <option value="Rejected">Rejected</option>
        </select>
      </div>

      {/* Table */}
      <table style={{ width: '100%', borderCollapse: 'collapse' }}>
        <thead>
          <tr style={{ backgroundColor: '#f4f4f4', textAlign: 'left' }}>
            <th style={thStyle} onClick={() => requestSort('customer')}>Customer {sortConfig.key === 'customer' ? (sortConfig.direction === 'asc' ? '↑' : '↓') : ''}</th>
            <th style={thStyle} onClick={() => requestSort('product')}>Product</th>
            <th style={thStyle} onClick={() => requestSort('date')}>Date {sortConfig.key === 'date' ? (sortConfig.direction === 'asc' ? '↑' : '↓') : ''}</th>
            <th style={thStyle} onClick={() => requestSort('status')}>Status</th>
            <th style={thStyle} onClick={() => requestSort('amount')}>Amount {sortConfig.key === 'amount' ? (sortConfig.direction === 'asc' ? '↑' : '↓') : ''}</th>
          </tr>
        </thead>
        <tbody>
          {filteredAndSortedClaims.map((claim) => (
            <tr key={claim.id} style={{ borderBottom: '1px solid #ddd' }}>
              <td style={tdStyle}>{claim.customer}</td>
              <td style={tdStyle}>{claim.product}</td>
              <td style={tdStyle}>{claim.date}</td>
              <td style={tdStyle}>
                <span style={{ 
                  padding: '4px 8px', 
                  borderRadius: '4px', 
                  fontSize: '12px',
                  backgroundColor: claim.status === 'Approved' ? '#d4edda' : claim.status === 'Rejected' ? '#f8d7da' : '#fff3cd'
                }}>
                  {claim.status}
                </span>
              </td>
              <td style={tdStyle}>${claim.amount}</td>
            </tr>
          ))}
        </tbody>
      </table>
      {filteredAndSortedClaims.length === 0 && <p>No claims found.</p>}
    </div>
  );
};

const thStyle = { padding: '12px', borderBottom: '2px solid #ddd', cursor: 'pointer', userSelect: 'none' };
const tdStyle = { padding: '12px' };

export default WarrantyClaimsTable;

