import unittest

def add(a, b):
    return a + b

class TestAdd(unittest.TestCase):
    # Test case for positive integers
    def test_add_positive_integers(self):
        self.assertEqual(add(1, 2), 3)

    # Test case for negative integers
    def test_add_negative_integers(self):
        self.assertEqual(add(-1, -1), -2)
        self.assertEqual(add(-1, 5), 4)

    # Test case for floating point numbers
    def test_add_floats(self):
        self.assertAlmostEqual(add(1.1, 2.2), 3.3, places=7)
        self.assertEqual(add(-1.5, 1.5), 0.0)

    # Test case for zero
    def test_add_zero(self):
        self.assertEqual(add(0, 0), 0)
        self.assertEqual(add(5, 0), 5)

    # Test case for string concatenation
    def test_add_strings(self):
        self.assertEqual(add("hello ", "world"), "hello world")

    # Test case for list concatenation
    def test_add_lists(self):
        self.assertEqual(add([1, 2], [3, 4]), [1, 2, 3, 4])

    # Test case for tuple concatenation
    def test_add_tuples(self):
        self.assertEqual(add((1, 2), (3, 4)), (1, 2, 3, 4))

    # Test case for large numbers
    def test_add_large_numbers(self):
        self.assertEqual(add(10**15, 10**15), 2 * 10**15)

    # Test case for incompatible types (Expecting TypeError)
    def test_add_incompatible_types(self):
        with self.assertRaises(TypeError):
            add(1, "string")
        with self.assertRaises(TypeError):
            add([1, 2], 3)

if __name__ == '__main__':
    unittest.main()

